using System;using System.IO;using System.Xml;using Newtonsoft.Json;using ICSharpCode.WpfDesign;namespace BgCommon.UI.Designer.Serialization{    /// <summary>    /// 序列化格式    /// </summary>    public enum SerializationFormat    {        /// <summary>        /// XML格式        /// </summary>        Xml,        /// <summary>        /// JSON格式        /// </summary>        Json    }        /// <summary>    /// 序列化管理器    /// </summary>    public class SerializationManager    {        private readonly DesignContext _context;                /// <summary>        /// 构造函数        /// </summary>        /// <param name="context">设计上下文</param>        public SerializationManager(DesignContext context)        {            _context = context;        }                /// <summary>        /// 保存设计        /// </summary>        /// <param name="path">文件路径</param>        /// <param name="format">序列化格式</param>        public void SaveDesign(string path, SerializationFormat format)        {            switch (format)            {                case SerializationFormat.Xml:                    SaveAsXml(path);                    break;                case SerializationFormat.Json:                    SaveAsJson(path);                    break;                default:                    throw new ArgumentException("不支持的序列化格式");            }        }                /// <summary>        /// 保存为XML格式        /// </summary>        /// <param name="path">文件路径</param>        private void SaveAsXml(string path)        {            using (var writer = XmlWriter.Create(path, new XmlWriterSettings { Indent = true }))            {                _context.Save(writer);            }        }                /// <summary>        /// 保存为JSON格式        /// </summary>        /// <param name="path">文件路径</param>        private void SaveAsJson(string path)        {            // 首先保存为XML字符串            using (var stringWriter = new StringWriter())            using (var xmlWriter = XmlWriter.Create(stringWriter, new XmlWriterSettings { Indent = true }))            {                _context.Save(xmlWriter);                var xmlContent = stringWriter.ToString();                                // 将XML转换为JSON                var xmlDoc = new XmlDocument();                xmlDoc.LoadXml(xmlContent);                var jsonContent = JsonConvert.SerializeXmlNode(xmlDoc, Newtonsoft.Json.Formatting.Indented);                                // 写入文件                File.WriteAllText(path, jsonContent);            }        }                /// <summary>        /// 加载设计        /// </summary>        /// <param name="path">文件路径</param>        /// <returns>设计上下文</returns>        public DesignContext LoadDesign(string path)        {            var extension = Path.GetExtension(path).ToLower();                        switch (extension)            {                case ".xml":                    return LoadFromXml(path);                case ".json":                    return LoadFromJson(path);                default:                    throw new ArgumentException("不支持的文件格式");            }        }                /// <summary>        /// 从XML加载设计        /// </summary>        /// <param name="path">文件路径</param>        /// <returns>设计上下文</returns>        private DesignContext LoadFromXml(string path)        {            using (var reader = XmlReader.Create(path))            {                var loadSettings = new ICSharpCode.WpfDesign.Designer.Xaml.XamlLoadSettings();                return new ICSharpCode.WpfDesign.Designer.Xaml.XamlDesignContext(reader, loadSettings);            }        }                /// <summary>        /// 从JSON加载设计        /// </summary>        /// <param name="path">文件路径</param>        /// <returns>设计上下文</returns>        private DesignContext LoadFromJson(string path)        {            // 读取JSON文件            var jsonContent = File.ReadAllText(path);                        // 将JSON转换为XML            var xmlDoc = JsonConvert.DeserializeXmlNode(jsonContent);                        // 加载XML到设计上下文            using (var stringReader = new StringReader(xmlDoc.OuterXml))            using (var xmlReader = XmlReader.Create(stringReader))            {                var loadSettings = new ICSharpCode.WpfDesign.Designer.Xaml.XamlLoadSettings();                return new ICSharpCode.WpfDesign.Designer.Xaml.XamlDesignContext(xmlReader, loadSettings);            }        }    }}